// Request + Response (Save, GetGridList, Action endpoints)
public abstract class TenantEndpoint<TRequest, TResponse> : Endpoint<TRequest, TResponse>
{
    protected Guid TenantId { get; private set; }
    protected Guid UserId { get; private set; }
    protected Guid RequestLanguageId { get; private set; }
    protected Guid DefaultLanguageId { get; private set; }

    public sealed override async Task HandleAsync(TRequest req, CancellationToken ct)
    {
        if (!TenantEndpointHelper.TryExtractClaims(
                HttpContext, out var tenantId, out var userId,
                out var requestLanguageId, out var defaultLanguageId))
        {
            await Send.UnauthorizedAsync(ct);
            return;
        }
        TenantId = tenantId;
        UserId = userId;
        RequestLanguageId = requestLanguageId;
        DefaultLanguageId = defaultLanguageId;
        await HandleValidatedRequestAsync(req, ct);
    }

    protected abstract Task HandleValidatedRequestAsync(TRequest req, CancellationToken ct);
}

// Request only, no response (Delete, Lifecycle endpoints)
public abstract class TenantEndpoint<TRequest> : Endpoint<TRequest> { ... }

// Response only, no request (Get single entity)
public abstract class TenantEndpointWithoutRequest<TResponse> : EndpointWithoutRequest<TResponse> { ... }

// No request or response (Lifecycle with no body)
public abstract class TenantEndpointWithoutRequest : EndpointWithoutRequest { ... }

public sealed class DeleteComplianceProfileEndpoint(DeleteComplianceProfileCommand command)
    : TenantEndpoint<DeleteComplianceProfileEndpointRequest>
{
    public override void Configure()
    {
        Delete("/api/v1/admin/compliance-profiles/{id}");
    }

    protected override async Task HandleValidatedRequestAsync(
        DeleteComplianceProfileEndpointRequest req, CancellationToken ct)
    {
        var result = await command.ExecuteAsync(req, TenantId, ct);
        if (result.Succeeded)
        {
            await Send.NoContentAsync(ct);
            return;
