public sealed class SaveActionEndpoint(
    SaveActionCommand saveCommand)
    : TenantEndpoint<SaveActionRequest, SaveActionResponse>
{
    public override void Configure()
    {
        Post("/api/v1/actions");
        Policies(ActionConstants.PolicyNames.ActionAdmin);
    }

    protected override async Task HandleValidatedRequestAsync(
        SaveActionRequest req, CancellationToken ct)
    {
        var result = await saveCommand.ExecuteAsync(
            req, UserId, RequestLanguageId, DefaultLanguageId, ct);
        if (!result.Succeeded)
        {
            await SendProblemAsync(result.Error!.Code, result.Error.StatusCode, result.Error.Message, ct);
            return;
        }

        var mapResult = result.Value!;
        var isNew = mapResult.NewItems.Count > 0;
        var entityId = isNew ? mapResult.NewItems[0].Id : mapResult.UpdatedItems[0].Id;

        if (isNew)
            await Send.CreatedAtAsync<GetActionEndpoint>(
                new { id = entityId },
                new SaveActionResponse(entityId), ct);
        else
            await Send.OkAsync(new SaveActionResponse(entityId), ct);
    }
}

