// Provides pagination and common search for simple entities
public class PagedRequest
{
    public int Page { get; set; } = 1;
    public int PageSize { get; set; } = 25;
    public string? Search { get; set; }
    public string? Status { get; set; }
}

// Response — lives in Nxgn.Actions.Contracts.Shared
public sealed record GridListResponse<T>(
    IReadOnlyList<T> Items,
    int TotalCount,
    int Page,
    int PageSize);

