public sealed class ActivateComplianceProfileEndpoint(
    ActivateComplianceProfileCommand activateCommand,
    GetComplianceProfileQuery getQuery,
    ComplianceProfileDTOMapper dtoMapper)
    : TenantEndpointWithoutRequest<ComplianceProfileDTO>
{
    public override void Configure()
    {
        Post("/api/v1/compliance-profiles/{id}/activate");
        Policies(ActionConstants.PolicyNames.ComplianceAdmin);
    }

    protected override async Task HandleValidatedRequestAsync(CancellationToken ct)
    {
        var id = Route<Guid>("id");

        var result = await activateCommand.ExecuteAsync(id, UserId, ct);
        if (!result.Succeeded)
        {
            await SendProblemAsync(result.Error!.Code, result.Error.StatusCode, result.Error.Message, ct);
            return;
        }

        var entity = await getQuery.ExecuteAsync(id, ct);
        await Send.OkAsync(
            dtoMapper.Map(entity!, RequestLanguageId, DefaultLanguageId), ct);
    }
}

